    ($q$prinses-panda$q$, $q$Prinses Panda se skoenlapper dans$q$, $q$Prinses Panda wil dans maar sukkel. Met hulp en oefening bereik sy haar droom.$q$, array[$q$Moenie opgee nie$q$, $q$Oefening en ondersteuning help jou groei$q$]::text[], array[$q$Deursettingsvermoë$q$, $q$selfvertroue$q$, $q$ondersteuning$q$]::text[], array[$q$deursettingsvermoë$q$, $q$selfvertroue$q$, $q$ondersteuning$q$]::text[], array[$q$Hoekom het Prinses Panda aanvanklik gesukkel?$q$, $q$Wie het haar gehelp?$q$, $q$Wat gebeur as ons aanhou oefen?$q$]::text[], array[$q$Prinses Panda$q$, $q$skoenlappertjie$q$, $q$flaminke$q$]::text[]),
    ($q$daantjie-en-sy-waentjie$q$, $q$Daantjie en sy waentjie$q$, $q$Daantjie hou aan om al hoe meer goed te versamel totdat sy waentjie te swaar raak en hom amper in gevaar bring. Hy leer om te deel en nie alles te wil hê nie.$q$, array[$q$Te veel hê kan probleme veroorsaak$q$, $q$Leer om te deel en nee te sê$q$]::text[], array[$q$Selfbeheersing$q$, $q$deel$q$, $q$tevredenheid$q$]::text[], array[$q$selfbeheersing$q$, $q$deel$q$, $q$tevredenheid$q$]::text[], array[$q$Hoekom wou Daantjie alles hê?$q$, $q$Wat het gebeur toe sy waentjie te swaar geword het?$q$, $q$Hoekom is dit goed om te deel?$q$]::text[], array[$q$Daantjie$q$]::text[]),
