    ($q$rammetjie-uitnek$q$, $q$Rammetjie Uitnek!$q$, $q$Rammetjie stamp ander maaitjies en maak hulle seer totdat hy self teen iemand groter vasloop en leer om sagter te speel.$q$, array[$q$Moenie ander seermaak nie$q$, $q$Leer uit jou foute$q$]::text[], array[$q$Respek$q$, $q$empatie$q$, $q$selfbeheer$q$]::text[], array[$q$respek$q$, $q$empatie$q$, $q$selfbeheer$q$]::text[], array[$q$Hoekom het die ander maaitjies nie van Rammetjie gehou nie?$q$, $q$Wat het gebeur toe hy vir Rudi Renoster ontmoet het?$q$, $q$Hoe kan ons mooi speel saam met ander?$q$]::text[], array[$q$Rammetjie Uitnek$q$, $q$Niklaas die Hasie$q$, $q$Stefaans die Hoenderhaan$q$, $q$Rudi Renoster$q$, $q$ander maaitjies$q$]::text[]),
    ($q$dit-was-jou-stert$q$, $q$Dit was jou stert!$q$, $q$Floris is baie nuuskierig, maar verstaan nie hoekom dinge breek nie—tot hy besef dit is sy eie stert wat die skade veroorsaak.$q$, array[$q$Wees bewus van jou eie optrede$q$, $q$Neem verantwoordelikheid vir wat jy doen$q$]::text[], array[$q$Selfbewustheid$q$, $q$verantwoordelikheid$q$, $q$leer$q$]::text[], array[$q$selfbewustheid$q$, $q$verantwoordelikheid$q$, $q$leer$q$]::text[], array[$q$Hoekom het dinge gebreek rondom Floris?$q$, $q$Hoe het hy uitgevind wat die probleem is?$q$, $q$Wat kan ons doen om meer bewus te wees van wat ons doen?$q$]::text[], array[$q$Floris Dinosaurus$q$]::text[]),
    ($q$nah-nah$q$, $q$Nah Nah-Nah boe boe!$q$, $q$Sussa seemeeu terg die see en speel rof totdat sy deur ‘n brander omgeslaan word en leer om versigtig en respekvol te wees.$q$, array[$q$Moenie roekeloos wees nie$q$, $q$Luister na waarskuwings$q$]::text[], array[$q$Respek$q$, $q$versigtigheid$q$, $q$gehoorsaamheid$q$]::text[], array[$q$respek$q$, $q$versigtigheid$q$, $q$gehoorsaamheid$q$]::text[], array[$q$Hoekom het Sussa in die moeilikheid beland?$q$, $q$Wat het haar boeta vir haar gesê?$q$, $q$Hoekom is dit belangrik om na waarskuwings te luister?$q$]::text[], array[$q$Sussa seemeeu$q$, $q$Boeta seemeeu$q$, $q$Mamma$q$, $q$Pappa$q$]::text[]),
    ($q$diekwaaigrommel$q$, $q$Die Kwaai Grommel$q$, $q$Grommel is heeltyd kwaai en baklei, maar dit blyk hy is net moeg. Nadat hy rus, voel hy beter.$q$, array[$q$Emosies kan kom van moegheid$q$, $q$Rus en selfversorging is belangrik$q$]::text[], array[$q$Selfbewustheid$q$, $q$emosionele intelligensie$q$, $q$sorg$q$]::text[], array[$q$selfbewustheid$q$, $q$emosionele intelligensie$q$, $q$sorg$q$]::text[], array[$q$Hoekom was Grommel so kwaai?$q$, $q$Wat het gebeur toe hy slaap?$q$, $q$Hoe voel jy wanneer jy baie moeg is?$q$]::text[], array[$q$Grommel$q$, $q$Boeta$q$, $q$Sussa$q$]::text[]),
    ($q$stewels$q$, $q$Stewels$q$, $q$Stewels voel uitgesluit omdat sy anders is, maar leer dat haar vrees haar terughou en vind uiteindelik vriende wanneer sy dit oorkom.$q$, array[$q$Moenie bang wees om nuwe dinge te probeer nie$q$, $q$Wees jouself en gee ander ‘n kans$q$]::text[], array[$q$Selfvertroue$q$, $q$aanvaarding$q$, $q$moed$q$]::text[], array[$q$selfvertroue$q$, $q$aanvaarding$q$, $q$moed$q$]::text[], array[$q$Hoekom het die ander flaminke vir Stewels vermy?$q$, $q$Waarvoor was Stewels bang?$q$, $q$Wat het verander toe sy haar stewels uittrek?$q$]::text[], array[$q$Stewels$q$, $q$ander flaminkies$q$, $q$mamma en pappa flaminke$q$]::text[]),
    ($q$die-buffel-baas$q$, $q$Die Buffel-baas$q$, $q$Mnr. De Buffel raak oorweldig deur werk en besluite totdat hy besef hy moet fokus op wat hy goed doen en hulp kry waar nodig.$q$, array[$q$Ken jou sterkpunte$q$, $q$Vra vir hulp en deel verantwoordelikheid$q$]::text[], array[$q$Samewerking$q$, $q$selfinsig$q$, $q$balans$q$]::text[], array[$q$samewerking$q$, $q$selfinsig$q$, $q$balans$q$]::text[], array[$q$Hoekom was Mnr. De Buffel ongelukkig?$q$, $q$Wat het hom gehelp om beter te voel?$q$, $q$Waarmee is jy goed en waarmee het jy hulp nodig?$q$]::text[], array[$q$Mnr. De Buffel$q$, $q$Ruben die rooibekrenostervoëltjie$q$, $q$verskeie diere (olifant$q$, $q$oerangoetang$q$, $q$sjimpansee$q$, $q$ens.)$q$]::text[]),
    ($q$oom-boom$q$, $q$Oom Boom$q$, $q$Oom Boom is ’n ou boom wat langs ’n voetpaadjie staan en deur die jaar kyk hoe kinders verbygaan. Hy beleef al vier seisoene—van die vrolike lente tot die stil, koue winter—en leer dat alles verander, maar dat goeie tye altyd weer terugkom.$q$, array[$q$Seisoene en moeilike tye gaan verby$q$, $q$Hoop bly altyd oor$q$]::text[], array[$q$Hoop$q$, $q$Geduld$q$, $q$Aanvaarding$q$]::text[], array[$q$hoop$q$, $q$geduld$q$, $q$aanvaarding$q$]::text[], array[$q$Watter seisoen hou jy die meeste van en hoekom?$q$, $q$Hoe het Oom Boom gevoel in die winter?$q$, $q$Wat gebeur altyd weer na die winter?$q$]::text[], array[$q$Oom Boom$q$, $q$kinders$q$, $q$Mamma’s$q$, $q$Pappa’s$q$]::text[]),
    ($q$die-fluistervarke$q$, $q$Die Fluistervarke$q$, $q$Drie wilde varkies hou daarvan om rof en hard te speel, maar hulle maak heeltyd hulle baba boetie wakker. Hulle leer om sagter te speel en verander selfs hul naam na die Fluistervarke—ten minste vir ’n rukkie!$q$, array[$q$Dink aan ander wanneer jy speel$q$, $q$Selfbeheer is belangrik$q$]::text[], array[$q$Respek$q$, $q$Selfbeheer$q$, $q$Omgee$q$]::text[], array[$q$respek$q$, $q$selfbeheer$q$, $q$omgee$q$]::text[], array[$q$Hoekom moes die varkies stiller speel?$q$, $q$Hoe kan jy speel sonder om ander te pla?$q$, $q$Wanneer is dit reg om hard te speel?$q$]::text[], array[$q$Ompel$q$, $q$Strompel$q$, $q$Snoet$q$, $q$baba boetie$q$, $q$Mamma Vark$q$]::text[]),
    ($q$haily-hasie-se-groentetuin$q$, $q$Hailey Hasie se groentetuin$q$, $q$Hailey Hasie werk hard in haar groentetuin, maar raak hartseer toe ’n maatjie lelik is met haar. Haar mamma verduidelik dat vriendskap soos ’n tuin is—dit vat liefde, moeite en sorg om te groei.$q$, array[$q$Ware vriendskap vat moeite$q$, $q$Wees eerste ’n goeie maatjie$q$]::text[], array[$q$Vriendskap$q$, $q$Empatie$q$, $q$Respek$q$]::text[], array[$q$vriendskap$q$, $q$empatie$q$, $q$respek$q$]::text[], array[$q$Wat maak ’n goeie maatjie?$q$, $q$Hoe kan jy iemand beter laat voel?$q$, $q$Wat beteken dit om ’n “saadjie” van vriendskap te plant?$q$]::text[], array[$q$Hailey Hasie$q$, $q$Mamma Hasie$q$, $q$maatjie$q$]::text[]),
    ($q$arno-arend-sprei-sy-vlerke$q$, $q$Arno Arend sprei sy vlerke$q$, $q$Arno, ’n jong visarend, wil leer vlieg soos sy pappa. Hy probeer oor en oor, al val hy baie keer, totdat hy uiteindelik daarin slaag om sy vlerke te sprei en te vlieg.$q$, array[$q$Moenie opgee nie$q$, $q$Oefening maak jou sterker$q$]::text[], array[$q$Deursettingsvermoë$q$, $q$Moed$q$, $q$Selfvertroue$q$]::text[], array[$q$deursettingsvermoë$q$, $q$moed$q$, $q$selfvertroue$q$]::text[], array[$q$Het jy al iets probeer wat moeilik was?$q$, $q$Hoe het Arno gevoel toe hy geval het?$q$, $q$Wat het hom gehelp om weer te probeer?$q$]::text[], array[$q$Arno Arend$q$, $q$Barend die Arend (Pappa)$q$, $q$Mamma Arend$q$]::text[]),
    ($q$maniere-wys-jou-spiere$q$, $q$Maniere wys jou spiere$q$, $q$Meneer Maniere leer dat goeie maniere soos spiere is—hoe meer jy dit gebruik, hoe sterker word dit. Hy oefen om vriendelik te wees, te deel en respek te wys, selfs wanneer dit moeilik is.$q$, array[$q$Goeie maniere maak ’n groot verskil$q$, $q$Kies om die regte ding te doen$q$]::text[], array[$q$Respek$q$, $q$Vriendelikheid$q$, $q$Verantwoordelikheid$q$]::text[], array[$q$respek$q$, $q$vriendelikheid$q$, $q$verantwoordelikheid$q$]::text[], array[$q$Wat is goeie maniere?$q$, $q$Wanneer is dit moeilik om goeie maniere te gebruik?$q$, $q$Hoe laat goeie maniere ander mense voel?$q$]::text[], array[$q$Meneer Maniere$q$, $q$kinders by die snoepwinkel$q$]::text[]),
    ($q$llama-llama-pajama-llama$q$, $q$Lama Lama Pajama Lama$q$, $q$Lama Lama dink hy weet alles en luister nie na sy mamma nie. Een dag gaan hy skool toe in sy pajamas en leer ’n belangrike les oor luister en respek.$q$, array[$q$Luister na jou ouers$q$, $q$Jy hoef nie altyd terug te praat nie$q$]::text[], array[$q$Respek$q$, $q$Luister$q$, $q$Nederigheid$q$]::text[], array[$q$respek$q$, $q$luister$q$, $q$nederigheid$q$]::text[], array[$q$Hoekom het Llama Llama in sy pajamas skool toe gegaan?$q$, $q$Wat sou jy anders gedoen het?$q$, $q$Hoekom is dit belangrik om te luister?$q$]::text[], array[$q$Lama Lama$q$, $q$Mama Lama$q$, $q$maats$q$, $q$Juffrou$q$]::text[]),
    ($q$sjimpie-se-simfonie$q$, $q$Sjimpie se Simfonie$q$, $q$Sjimpie droom daarvan om ’n groot dirigent te wees, al spot die ander ape met hom. Na ’n groot val beland hy op ’n verhoog waar hy sy droom uitleef en almal verstom.$q$, array[$q$Glo in jou drome$q$, $q$Moenie luister na negatiewe stemme nie$q$]::text[], array[$q$Selfvertroue$q$, $q$Droom$q$, $q$Volharding$q$]::text[], array[$q$selfvertroue$q$, $q$droom$q$, $q$volharding$q$]::text[], array[$q$Wat is jou droom?$q$, $q$Hoe het Sjimpie gevoel toe ander vir hom gelag het?$q$, $q$Wat het gebeur toe hy nie opgegee het nie?$q$]::text[], array[$q$Sjimpie$q$, $q$ander ape$q$, $q$orkes$q$]::text[]),
    ($q$seekoei-sluit-sy-mond-toe$q$, $q$Seekoei sluit sy mond toe$q$, $q$Swys wil nie sy kos eet nie en dink dit lyk snaaks. Later voel hy siek en leer dat kos belangrik is om jou liggaam sterk en gesond te hou.$q$, array[$q$Eet jou kos om gesond te bly$q$, $q$Probeer eers voordat jy besluit$q$]::text[], array[$q$Gesondheid$q$, $q$Gehoorsaamheid$q$, $q$Verantwoordelikheid$q$]::text[], array[$q$gesondheid$q$, $q$gehoorsaamheid$q$, $q$verantwoordelikheid$q$]::text[], array[$q$Hoekom wou Swys nie eet nie?$q$, $q$Hoe het hy gevoel toe hy nie geëet het nie?$q$, $q$Hoekom is kos belangrik?$q$]::text[], array[$q$Swys Seekoei$q$, $q$Mamma Seekoei$q$, $q$Pappa Seekoei$q$]::text[]),
    ($q$grotman-grootman$q$, $q$Grotman Grootman$q$, $q$Grotman is baie skaam en bly alleen in sy grot. Hy leer om dapper te wees en uiteindelik maak hy ’n maatjie$q$, array[$q$Dit vat moed om uit jou dop te kom$q$, $q$Vriendskap begin met ’n eerste tree$q$]::text[], array[$q$Moed$q$, $q$Vriendskap$q$, $q$Selfvertroue$q$]::text[], array[$q$moed$q$, $q$vriendskap$q$, $q$selfvertroue$q$]::text[], array[$q$Hoekom was Grotman skaam?$q$, $q$Wat het hom gehelp om dapper te wees?$q$, $q$Hoe maak ’n mens nuwe maatjies?$q$]::text[], array[$q$Grotman$q$, $q$Dot die dinosourus$q$]::text[]),
    ($q$blommetjie-blom-astertjie-vaal$q$, $q$Blommetjie Blom & Astertjie Vaal$q$, $q$Blommetjie is vrolik en dol oor die son, maar haar sussie, Astertjie Vaal, is altyd moeg en hartseer. Blommetjie ontdek dat sy onbewustelik al die sonlig vir haarself opeis. Sy leer om te deel.$q$, array[$q$Wees bedagsaam en maak seker daar is plek vir almal$q$, $q$Praat met mekaar om uit te vind hoekom iemand hartseer is$q$]::text[], array[$q$Deelsaamheid$q$, $q$Empatie$q$, $q$Bedagsaamheid$q$, $q$Liefde$q$]::text[], array[$q$deelsaamheid$q$, $q$empatie$q$, $q$bedagsaamheid$q$, $q$liefde$q$]::text[], array[$q$Hoe dink jy het Astertjie gevoel toe sy in die skaduwee moes staan?$q$, $q$Wat kan ons doen om seker te maak almal geniet dit as ons saam speel?$q$, $q$Hoekom is dit belangrik om te vra "hoekom" as iemand nie wil saamspeel nie?$q$]::text[], array[$q$Blommetjie: Die vrolike, energieke sussie$q$, $q$Astertjie Vaal: Die skaam, stil sussie$q$, $q$Die Son: Die wyse raadgewer$q$]::text[]),
    ($q$schink-stories-blommetjie-blom-astertjie-vaal$q$, $q$Blommetjie Blom & Astertjie Vaal$q$, $q$Blommetjie is vrolik en dol oor die son, maar haar sussie, Astertjie Vaal, is altyd moeg en hartseer. Blommetjie ontdek dat sy onbewustelik al die sonlig vir haarself opeis. Sy leer om te deel.$q$, array[$q$Wees bedagsaam en maak seker daar is plek vir almal$q$, $q$Praat met mekaar om uit te vind hoekom iemand hartseer is$q$]::text[], array[$q$Deelsaamheid$q$, $q$Empatie$q$, $q$Bedagsaamheid$q$, $q$Liefde$q$]::text[], array[$q$deelsaamheid$q$, $q$empatie$q$, $q$bedagsaamheid$q$, $q$liefde$q$]::text[], array[$q$Hoe dink jy het Astertjie gevoel toe sy in die skaduwee moes staan?$q$, $q$Wat kan ons doen om seker te maak almal geniet dit as ons saam speel?$q$, $q$Hoekom is dit belangrik om te vra "hoekom" as iemand nie wil saamspeel nie?$q$]::text[], array[$q$Blommetjie: Die vrolike, energieke sussie$q$, $q$Astertjie Vaal: Die skaam, stil sussie$q$, $q$Die Son: Die wyse raadgewer$q$]::text[]),
    ($q$die-cool-krokodil$q$, $q$Die Cool Krokodil$q$, $q$Cool Krokodil dink sy gadgets en "cool" klere is belangriker as om saam met sy maats in die modder te speel. Hy besef egter vinnig dat hy eensaam is en dat ware pret en vriendskap baie beter is as om alleen voor ’n skerm te sit.$q$, array[$q$Vriendskap is belangriker as materiële goed$q$, $q$Moenie bang wees om vuil te word en saam te baljaar nie$q$]::text[], array[$q$Vriendskap$q$, $q$Balans$q$, $q$Nederigheid$q$]::text[], array[$q$vriendskap$q$, $q$balans$q$, $q$nederigheid$q$]::text[], array[$q$Dink jy Cool Krokodil was gelukkiger met sy foon of saam met sy maats?$q$, $q$Hoekom wou hy eers nie in die modder speel nie?$q$, $q$Wat is die lekkerste "gewone" ding wat jy saam met jou maats doen?$q$]::text[], array[$q$Cool Krokodil$q$, $q$Krokodil-maats$q$]::text[]),
    ($q$schink-stories-die-cool-krokodil$q$, $q$Die Cool Krokodil$q$, $q$Cool Krokodil dink sy gadgets en "cool" klere is belangriker as om saam met sy maats in die modder te speel. Hy besef egter vinnig dat hy eensaam is en dat ware pret en vriendskap baie beter is as om alleen voor ’n skerm te sit.$q$, array[$q$Vriendskap is belangriker as materiële goed$q$, $q$Moenie bang wees om vuil te word en saam te baljaar nie$q$]::text[], array[$q$Vriendskap$q$, $q$Balans$q$, $q$Nederigheid$q$]::text[], array[$q$vriendskap$q$, $q$balans$q$, $q$nederigheid$q$]::text[], array[$q$Dink jy Cool Krokodil was gelukkiger met sy foon of saam met sy maats?$q$, $q$Hoekom wou hy eers nie in die modder speel nie?$q$, $q$Wat is die lekkerste "gewone" ding wat jy saam met jou maats doen?$q$]::text[], array[$q$Cool Krokodil$q$, $q$Krokodil-maats$q$]::text[]),
    ($q$koalbeertjie-klou$q$, $q$Koalabeertjie Klou!$q$, $q$Wouter is opgewonde maar ook vreeslik bang vir sy eerste skooldag. Hy klou aan sy mamma se been, maar vind vinnig uit dat die skool propvol pret en nuwe maats is—soveel so dat hy aan die einde nie wil huis toe gaan nie!$q$, array[$q$Dit is oukei om bang te wees vir nuwe dinge$q$, $q$Skool is ’n plek van avontuur en nuwe vriende$q$]::text[], array[$q$Moed$q$, $q$Selfvertroue$q$, $q$Aanpassing$q$]::text[], array[$q$moed$q$, $q$selfvertroue$q$, $q$aanpassing$q$]::text[], array[$q$Waarom wou Wouter aan die begin aan Mamma se been klou?$q$, $q$Hoe het sy gevoel oor die skool verander aan die einde van die dag?$q$, $q$Waaraan het hy geklou toe dit tyd was om huis toe te gaan?$q$]::text[], array[$q$Wouter Koala$q$, $q$Juffrou Roux$q$, $q$Mamma en Pappa Koala$q$]::text[]),
    ($q$ompeplompie-obbelop$q$, $q$Ompeplompie Obbelop$q$, $q$Ompeplompie hou vreeslik baie van lekkergoed! Op ‘n dag ontdek hy die groottse hoop soetgoed wat hy al ooit gesien het en hy leer toe ook ‘n baie waardvolle lees! “Oe, schweeties!”$q$, array[$q$Matigheid is belangrik met soetgoed$q$, $q$Jou liggaam het gesonde kos nodig om reg te werk$q$]::text[], array[$q$Selfbeheersing$q$, $q$Gesondheid$q$, $q$Gehoorsaamheid$q$]::text[], array[$q$selfbeheersing$q$, $q$gesondheid$q$, $q$gehoorsaamheid$q$]::text[], array[$q$Wat het met Ompeplompie se magie gebeur nadat hy die lekkers geëet het?$q$, $q$Wat het hy geleer oor gesonde kos soos groente en water?$q$, $q$Wanneer is dit die beste tyd om ’n bietjie soetgoed te geniet?$q$]::text[], array[$q$Ompeplompie Obbelop$q$]::text[]),
    ($q$kantwieletjies$q$, $q$Kantwieletjies$q$, $q$’n Klein dogtertjie leer om sonder kantwieletjies fiets te ry met haar Pappa se hulp. Dit voel “Wobbely” wanneer Pappa haar fiets los. Maar, met Pappa se aanmoediging help hy haar om braaf te wees.$q$, array[$q$Moenie opgee as iets die eerste keer "wobbely" voel nie$q$, $q$Jou ouers glo in jou, selfs wanneer hulle jou vryheid gee$q$]::text[], array[$q$Deursettingsvermoë$q$, $q$Vertroue$q$, $q$Braafheid$q$]::text[], array[$q$deursettingsvermoë$q$, $q$vertroue$q$, $q$braafheid$q$]::text[], array[$q$Hoe het die kind gevoel toe die kantwieletjies afgehaal is?$q$, $q$Wat het die kind help ry toe Pappa se hand weg is?$q$, $q$Hoe help dit jou as jy weet iemand is "aan jou kant"?$q$]::text[], array[$q$Die kind$q$, $q$Pappa$q$]::text[]),
    ($q$ek-hou-nie-van-partytjies-nie$q$, $q$Ek hou nie van partytjies nie$q$, $q$Braam die beer hou van stilte en die natuur, maar sy maats reël ’n raserige verrassingspartytjie. Braam leer sy maats dat hy anders is, en sy vriende leer om hom te vier op ’n manier waarvan hý hou.$q$, array[$q$Respekteer dat mense se behoeftes verskil$q$, $q$Luister na wat jou vriende regtig gelukkig maak$q$]::text[], array[$q$Respek$q$, $q$Individualiteit$q$, $q$Luister$q$]::text[], array[$q$respek$q$, $q$individualiteit$q$, $q$luister$q$]::text[], array[$q$Waarom het Braam uit sy eie partytjie weggestap?$q$, $q$Hoe het sy maats gewys dat hulle hom regtig verstaan?$q$, $q$Wat sou jou ideale "partytjie" wees?$q$]::text[], array[$q$Braam die Beer$q$, $q$Braam se vriende$q$]::text[]),
    ($q$hey-pou$q$, $q$Hey Pou!$q$, $q$Pou dink hy is die heel mooiste en praat net oor homself sonder om vir sy maats ’n kans te gee. Deur sy gesprek met Eend leer hy dat ware vriendskap beteken om belang te stel in ander en ook te luister.$q$, array[$q$’n Gesprek gaan oor praat én luister$q$, $q$Moenie net oor jouself spog nie; gee ander ’n kans$q$]::text[], array[$q$Nederigheid$q$, $q$Vriendskap$q$, $q$Mededeelsaamheid$q$]::text[], array[$q$nederigheid$q$, $q$vriendskap$q$, $q$mededeelsaamheid$q$]::text[], array[$q$Hoekom het die ander voëls moeg geword vir Pou se praatjies?$q$, $q$Wat het Eend vir Pou geleer oor "saam" praat?$q$, $q$Hoe voel dit as iemand vir jou vra: "Hoe gaan dit met jou?"$q$]::text[], array[$q$Pou$q$, $q$Eend$q$, $q$Gans$q$, $q$Hoender$q$]::text[]),
    ($q$robot-doen-reg$q$, $q$Robot doen reg!$q$, $q$Bip die Robot leer om sy "liggies" te gebruik om te kies tussen reg en verkeerd. Hy leer om nie terug te stamp nie, om nie ander se goed te breek nie en om ’n hondjie in nood te help.$q$, array[$q$Dink (geel liggie) voor jy optree$q$, $q$Kies altyd om die regte ding te doen, selfs as dit moeilik is$q$]::text[], array[$q$Integriteit$q$, $q$Selfbeheersing$q$, $q$Vriendelikheid$q$]::text[], array[$q$integriteit$q$, $q$selfbeheersing$q$, $q$vriendelikheid$q$]::text[], array[$q$Wat beteken dit as Bip se liggie rooi word? En groen?$q$, $q$Waarom het Bip besluit om nie die sandkasteel te breek nie?$q$, $q$Hoe het Bip vir Pote die hondjie gehelp?$q$]::text[], array[$q$Bip Robot$q$, $q$Tin Robot$q$, $q$Boe-bot$q$, $q$Pote die hondjie$q$]::text[]),
    ($q$schink-stories-babbelbessie$q$, $q$Babbelbessie$q$, $q$Babbelbessie praat so baie dat sy nooit luister nie. Nadat sy seep insluk en net borrels kan blaas, word sy noodgedwonge stil en besef sy hoe belangrik dit is om mooi te dink voor mens praat.$q$, array[$q$As jy te veel praat, hoor jy nie die mooi dinge om jou nie$q$, $q$Ander mense luister beter as jy ook vir hulle ’n kans gee$q$]::text[], array[$q$Luister$q$, $q$Selfbeheersing$q$, $q$Bedagsaamheid$q$]::text[], array[$q$luister$q$, $q$selfbeheersing$q$, $q$bedagsaamheid$q$]::text[], array[$q$Wat het gebeur toe Babbelbessie probeer praat nadat sy die seep ingesluk het?$q$, $q$Wat het sy gehoor toe sy uiteindelik stil raak?$q$, $q$Hoekom is dit belangrik om eers te dink voor jy praat?$q$]::text[], array[$q$Babbelbessie$q$, $q$Oom Skilpad$q$, $q$Die Kiewiete$q$]::text[]),
    ($q$schink-stories-02-ai-piesang$q$, $q$Ai Piesang$q$, $q$Piesang is emosioneel en weet nie hoe om sy gevoelens te hanteer nie. Hy leer dat ’n diep asemhaling en om sy emosies te erken ("Ai Piesang!") hom help om weer kalm en gelukkig te word.$q$, array[$q$Dit is oukei om groot emosies te hê$q$, $q$Haal diep asem en praat met ’n vriend as jy oorweldig voel$q$]::text[], array[$q$Emosionele intelligensie$q$, $q$Kalmte$q$, $q$Vriendskap$q$]::text[], array[$q$emosionele intelligensie$q$, $q$kalmte$q$, $q$vriendskap$q$]::text[], array[$q$Hoe het Piesang se lyf gevoel toe hy so ontsteld was?$q$, $q$Wat het Suurlemoentjie vir hom geleer om te doen?$q$, $q$Wat kan jy sê of doen as jy voel jou emosies word te groot?$q$]::text[], array[$q$Piesang$q$, $q$Suurlemoentjie$q$, $q$Pomelo$q$, $q$Mango en Perske$q$]::text[]),
    ($q$die-kat-wat-alles-vat$q$, $q$Die Kat wat alles vat$q$, $q$Kieter Kat kan nie help om dinge te vat wat nie aan hom behoort nie, nie omdat hy dit wil hê nie, maar omdat hy die aandag en lof soek. Wanneer hy ’n trofee steel en maak asof hy ’n kompetisie gewen het, leer hy dat die skuldgevoel en die leuen swaarder weeg as die eer.$q$, array[$q$Eerlikheid is altyd die beste beleid$q$, $q$Roem wat op leuens gebou is, maak mens nie gelukkig nie$q$, $q$Erken jou foute en aanvaar die gevolge om dinge reg te stel$q$]::text[], array[$q$Eerlikheid$q$, $q$Integriteit$q$, $q$Verantwoordelikheid$q$]::text[], array[$q$eerlikheid$q$, $q$integriteit$q$, $q$verantwoordelikheid$q$]::text[], array[$q$Waarom het Kieter die trofee gevat as hy nie regtig wou wen nie?$q$, $q$Hoe het Kieter gevoel toe almal hom toejuig vir iets wat hy nie gedoen het nie?$q$, $q$Wat het gebeur toe Kieter uiteindelik die waarheid vertel het?$q$]::text[], array[$q$Kieter Kat$q$, $q$Tier (die wenner)$q$, $q$Die Skare$q$, $q$Die Polisie$q$]::text[]),
    ($q$dankie-en-die-mislukke-skree$q$, $q$Dankie en Die Mislukke Skree$q$, $q$In Woordjieland is "Dankie" almal se maat, maar "Die Mislukke Skree" is alleen omdat hy net op almal skree om sy sin te kry. Dankie leer hom dat mooi woorde harte sag maak, en gou verander sy naam (en sy gedrag) na iets baie mooier: "Asseblief".$q$, array[$q$Goeie maniere en mooi woorde help jou om maats te maak$q$, $q$Jy kry meer reg met vriendelikheid as met skree en stamp$q$]::text[], array[$q$Vriendelikheid$q$, $q$Respek$q$, $q$Goeie Maniere$q$]::text[], array[$q$vriendelikheid$q$, $q$respek$q$, $q$goeie maniere$q$]::text[], array[$q$Waarom wou niemand saam met Die Mislukke Skree speel nie?$q$, $q$Wat het Dankie vir hom gesê wat hom laat dink het?$q$, $q$Hoe het sy nuwe naam, "Asseblief", sy lewe verander?$q$]::text[], array[$q$Dankie$q$, $q$Die Mislukke Skree (later Asseblief)$q$]::text[]),
    ($q$schink-stories-dankie-en-die-mislukke-skree$q$, $q$Dankie en Die Mislukke Skree$q$, $q$In Woordjieland is "Dankie" almal se maat, maar "Die Mislukke Skree" is alleen omdat hy net op almal skree om sy sin te kry. Dankie leer hom dat mooi woorde harte sag maak, en gou verander sy naam (en sy gedrag) na iets baie mooier: "Asseblief".$q$, array[$q$Goeie maniere en mooi woorde help jou om maats te maak$q$, $q$Jy kry meer reg met vriendelikheid as met skree en stamp$q$]::text[], array[$q$Vriendelikheid$q$, $q$Respek$q$, $q$Goeie Maniere$q$]::text[], array[$q$vriendelikheid$q$, $q$respek$q$, $q$goeie maniere$q$]::text[], array[$q$Waarom wou niemand saam met Die Mislukke Skree speel nie?$q$, $q$Wat het Dankie vir hom gesê wat hom laat dink het?$q$, $q$Hoe het sy nuwe naam, "Asseblief", sy lewe verander?$q$]::text[], array[$q$Dankie$q$, $q$Die Mislukke Skree (later Asseblief)$q$]::text[]),
    ($q$die-kwaai-bok-sit-vas$q$, $q$Kwaaibok sit vas!$q$, $q$Kwaaibok is altyd kwaad vir die wêreld. Wanneer hy uit woede ’n boomtak probeer wegstamp, sit dit in sy horings vas. Hy probeer almal beveel om hom te help, maar sy lelike houding jaag hulle weg. Eers wanneer hy sagkens vra, help Arend hom om vry te kom.$q$, array[$q$Om kwaad te wees help jou nie om probleme op te los nie$q$, $q$Mense help jou graag as jy mooi vra, maar nie as jy op hulle skree nie$q$]::text[], array[$q$Geduld$q$, $q$Nederigheid$q$, $q$Dankbaarheid$q$]::text[], array[$q$geduld$q$, $q$nederigheid$q$, $q$dankbaarheid$q$]::text[], array[$q$Waarom wou die voëltjies en die hasie nie vir Kwaaibok help nie?$q$, $q$Wat moes Kwaaibok anders doen voordat Arend hom gehelp het?$q$, $q$Wat het Kwaaibok aan die einde vir Arend gesê?$q$]::text[], array[$q$Kwaaibok$q$, $q$Dassie$q$, $q$Voëltjies$q$, $q$Hasie$q$, $q$Arend$q$]::text[]),
    ($q$vlakkie-die-bosbakkie$q$, $q$Vlakkie die Bosbakkie$q$, $q$Vlakkie lyk dalk anders met sy vlakvark-snoet, en hy is nie so vinnig soos die blink sportmotors nie. Maar wanneer die sportmotors op die grondpad vasval, is dit Vlakkie se krag en ontwerp wat die dag red. Hy leer hulle dat almal uniek is en dat spesiale talente op die regte tyd blink.$q$, array[$q$Moenie ander spot omdat hulle anders lyk of stadiger is nie$q$, $q$Almal is goed met iets anders; waardeer mekaar se unieke kragte$q$]::text[], array[$q$Hulpvaardigheid$q$, $q$Dapperheid$q$, $q$Respek$q$, $q$Selfvertroue$q$]::text[], array[$q$hulpvaardigheid$q$, $q$dapperheid$q$, $q$respek$q$, $q$selfvertroue$q$]::text[], array[$q$Waarom het die sportmotors vir Vlakkie gelag?$q$, $q$Wat het gebeur toe die motors op die grondpad moes ry?$q$, $q$Hoe het Vlakkie gewys dat hy ’n goeie hart het, selfs nadat hulle lelik was?$q$]::text[], array[$q$Vlakkie die Bosbakkie$q$, $q$Oom Trok$q$, $q$Steve$q$, $q$Stefaans en Streep (Sportmotors)$q$]::text[]),
    ($q$klippie-de-klop$q$, $q$Klippie De Klop$q$, $q$Klippie de Klop reis die hele wêreld vol—van die Eiffeltoring tot in die koue Antarktika—op soek na die perfekte, vreedsame blyplek. Na ’n groot avontuur deur lande en kulture, vind hy uiteindelik sy rusplek onder ’n boom op ’n mooi heuwel.$q$, array[$q$Die wêreld is groot en vol wonderlike plekke om te verken$q$, $q$Soms moet mens ver reis om te vind waarna jou hart soek$q$]::text[], array[$q$Avontuur$q$, $q$Nuuskierigheid$q$, $q$Tevredeheid$q$]::text[], array[$q$avontuur$q$, $q$nuuskierigheid$q$, $q$tevredeheid$q$]::text[], array[$q$Watter lande of plekke wat Klippie besoek het, klink vir jou die lekkerste?$q$, $q$Waarna was Klippie eintlik op soek tydens sy reis?$q$, $q$Waar het Klippie uiteindelik sy vrede gevind?$q$]::text[], array[$q$Klippie de Klop$q$]::text[]),
    ($q$reenboog-robot$q$, $q$Reënboog Robot$q$, $q$Reënboog Robot het ’n spesiale drukkertjie wat prentjies maak van dit waarna sy luister. Wanneer al haar maatjies gelyk oor mekaar praat, raak haar stelsel deurmekaar en druk sy ’n gemors uit. Die robotte leer dat hulle mekaar ’n kans moet gee om te praat sodat almal gehoor kan word.$q$, array[$q$Luister beteken om vir jou beurt te wag$q$, $q$Kommunikasie werk die beste as ons een-op-’n-slag praat$q$]::text[], array[$q$Geduld$q$, $q$Kommunikasie$q$, $q$Samewerking$q$]::text[], array[$q$geduld$q$, $q$kommunikasie$q$, $q$samewerking$q$]::text[], array[$q$Waarom het Reënboog Robot se drukkertjie begin rook?$q$, $q$Hoe het die prentjie gelyk toe almal gelyk gepraat het?$q$, $q$Wat het die robotte geleer oor "beurte maak"?$q$]::text[], array[$q$Reënboog Robot$q$, $q$Ren Robot$q$, $q$Groenie Robot$q$, $q$Kaptein Robot$q$]::text[]),
    ($q$toekie-toekan$q$, $q$Toekie die Toekan$q$, $q$Toekie is só nuuskierig dat hy sy lang snawel oral indruk waar dit nie hoort nie—dikwels met rampspoedige gevolge vir sy maats. Wanneer hy egter sy snawel in ’n boomholte vasdruk, leer hy dat nuuskierigheid perke het en dat mens nie in ander se sake moet krap nie.$q$, array[$q$Moenie jou neus (of snawel!) in ander se sake steek nie$q$, $q$Respekteer ander se privaatheid en besittings$q$]::text[], array[$q$Respek$q$, $q$Selfbeheersing$q$, $q$Bedagsaamheid$q$]::text[], array[$q$respek$q$, $q$selfbeheersing$q$, $q$bedagsaamheid$q$]::text[], array[$q$Wat het met Pietman se koerant en Hessie se bessie gebeur as gevolg van Toekie?$q$, $q$Hoe het Toekie in die boomholte vasgesit?$q$, $q$Is dit altyd goed om nuuskierig te wees, of kan dit probleme maak?$q$]::text[], array[$q$Toekie die Toekan$q$, $q$Pietman Papegaai$q$, $q$Hessie die Loerie$q$, $q$Die stoute Kolibri$q$]::text[]),
    ($q$rakker-en-die-ruimte$q$, $q$Rakker en die Ruimte$q$, $q$Rakker is mal oor die ruimte en vertel die wildste opmaakstories oor sy ruimte-avonture om sy maats te beïndruk. Wanneer ’n regte ruimtevaarder die klas besoek, leer Rakker dat die waarheid baie kragtiger is as versinsels. Hy besluit om op te hou spog en liewer hard te leer om eendag sy drome waar te maak.$q$, array[$q$Vertel die waarheid, want leuens vang jou altyd uit$q$, $q$Jy hoef nie stories op te maak om indrukwekkend te wees nie$q$, $q$Ware drome word waar deur harde werk en leer$q$]::text[], array[$q$Eerlikheid$q$, $q$Integriteit$q$, $q$Deursettingsvermoë$q$]::text[], array[$q$eerlikheid$q$, $q$integriteit$q$, $q$deursettingsvermoë$q$]::text[], array[$q$Waarom dink jy het Rakker stories opgemaak oor die ruimte?$q$, $q$Hoe het Rakker gevoel toe die oom hom vra of hy al op die maan was?$q$, $q$Wat het Rakker aan die einde gedoen om dinge reg te stel met sy klas?$q$]::text[], array[$q$Rakker$q$, $q$Die Ruimtevaarder-oom$q$, $q$Die Klasmaats$q$]::text[]),
    ($q$dinosaurus-is-moeg$q$, $q$Dinosaurus is moeg$q$, $q$’n Reuse Bracheosaurus is doodmoeg, maar hy probeer desperaat om wakker te bly. Hy strompel en gaap deur die veld totdat hy uiteindelik besef dat sy lyf rus nodig het. Die storie wys op ’n snaakse manier hoe belangrik dit is om betyds bed toe te gaan sodat jou liggaam weer kan herstel.$q$, array[$q$Jou liggaam het slaap nodig om gesond en sterk te bly$q$, $q$Moenie veg teen die vaak nie; rus is jou maat$q$]::text[], array[$q$Selfsorg$q$, $q$Gesondheid$q$, $q$Dissipline$q$]::text[], array[$q$selfsorg$q$, $q$gesondheid$q$, $q$dissipline$q$]::text[], array[$q$Waaraan kon mens sien dat die dinosaurus baie moeg was?$q$, $q$Wat was die dinosaurus se verskoning waarom hy nie wou gaan slaap nie?$q$, $q$Hoe het hy gevoel nadat hy uiteindelik in die gras aan die slaap geraak het?$q$]::text[], array[$q$Die Bracheosaurus$q$]::text[]),
    ($q$schink-stories-dankie-en-die-lelike-praat$q$, $q$Dankie en die Lelike Praat$q$, $q$"Die Lelike Praat" gebruik sy woorde om ander te spot en seer te maak. Dankie, die vriendelike woordjie, leer hom dat lelike woorde soos dorings is, maar dat mooi woorde ander (en jouself) beter laat voel. Die Lelike Praat leer om sy woorde te verander om ander op te bou.$q$, array[$q$Woorde het krag: kies om ander op te bou, nie af te breek nie$q$, $q$As jy mooi praat met ander, voel jy self ook gelukkiger$q$]::text[], array[$q$Vriendelikheid$q$, $q$Respek$q$, $q$Empatie$q$]::text[], array[$q$vriendelikheid$q$, $q$respek$q$, $q$empatie$q$]::text[], array[$q$Hoe het die ander woordjies gevoel wanneer Lelike Praat met hulle gepraat het?$q$, $q$Wat het Dankie gedoen toe Lelike Praat vir hom sê hy is "simpel"?$q$, $q$Wat is sy nuwe naam aan die einde van die storie?$q$]::text[], array[$q$Dankie$q$, $q$Die Lelike Praat (later Mooi Praat)$q$]::text[]),
    ($q$die-bang-soldaatjie$q$, $q$Die Bang Soldaatjie$q$, $q$’n Soldaatjie is vreesbevange vir die donker en sy verbeelding laat alles soos monsters lyk. Wanneer hy alleen in die nag na die kamp moet terugstap, leer hy om sy vrees in die gesig te kyk. Hy besef dat die dinge waarvoor hy bang was, eintlik net gewone voorwerpe is en dat hy dapperder is as wat hy gedink het.$q$, array[$q$Vrees is dikwels net jou verbeelding wat met jou speel$q$, $q$Dapperheid beteken nie dat jy nie bang is nie, maar dat jy aanhou stap al is jy bang$q$]::text[], array[$q$Moed$q$, $q$Deursettingsvermoë$q$, $q$Selfvertroue$q$]::text[], array[$q$moed$q$, $q$deursettingsvermoë$q$, $q$selfvertroue$q$]::text[], array[$q$In wat het die soldaatjie se verbeelding die bokke en die kraak in die pad verander?$q$, $q$Wat het die soldaatjie gedoen om dapper te wees?$q$, $q$Is dit oukei om soms bang te voel?$q$]::text[], array[$q$Die Bang Soldaatjie$q$, $q$Die Sersant$q$, $q$Die Luitenant$q$, $q$Die Bataljon$q$]::text[]),
    ($q$modderman$q$, $q$Modderman$q$, $q$Modderman wil vreeslik graag maats hê, maar sy modderige drukkies jaag almal weg. Nadat hy per ongeluk sy "merk" op sy maats se prente los, besef hulle dat hy nie vuil is nie, maar net deel wil wees van hulle groepie. Hulle leer om hom te aanvaar net soos hy is en vind ’n nuwe manier om saam te speel.$q$, array[$q$Elke maat is soms ’n bietjie “vreemder” as jy eer,$q$, $q$Maar as jy kyk met ’n maatjie-hart,$q$, $q$Sal jy sien: ons is almal deel van mekaar se kunswerk – elke deel, elke part$q$]::text[], array[$q$Aanvaarding$q$, $q$Vriendskap$q$, $q$Inklusiwiteit$q$]::text[], array[$q$aanvaarding$q$, $q$vriendskap$q$, $q$inklusiwiteit$q$]::text[], array[$q$Waarom wou die maats aan die begin nie vir Modderman naby hulle hê nie?$q$, $q$Hoe het Blaartjie besef dat Modderman eintlik ’n maatjie is?$q$, $q$Wat is hulle nuwe manier om mekaar te groet sonder om heeltemal vol modder te word?$q$]::text[], array[$q$Modderman$q$, $q$Blaartjie$q$, $q$Klippie$q$, $q$Takkie$q$]::text[]),
    ($q$nah-nah-boem-bons$q$, $q$Nah nah Boem Bons!$q$, $q$Donsie die klein seemeeu dink hy is vreeslik braaf en terg die branders met sy "Nah nah!". Maar die see is groot en sterk. Wanneer 'n groot brander hom tref, moet sy grootboet hom help. Donsie leer dat die natuur gerespekteer moet word en dat selfvertroue nie dieselfde as roekeloosheid is nie.$q$, array[$q$Respekteer die natuur en die krag van die see$q$, $q$Luister na die waarskuwings van diegene wat reeds lesse geleer het$q$, $q$Die branders is pragtig, maar hulle is nie jou "speelmaat" nie – wees versigtig$q$]::text[], array[$q$Respek vir die natuur$q$, $q$Veiligheid$q$, $q$Gehoorsaamheid$q$]::text[], array[$q$respek vir die natuur$q$, $q$veiligheid$q$, $q$gehoorsaamheid$q$]::text[], array[$q$Hoekom het Donsie gedink hy kan die branders terg?$q$, $q$Wie het hom gehelp toe hy omgeval het?$q$, $q$Wat beteken die woorde: "Die branders is nie jou maat nie"?$q$]::text[], array[$q$Donsie$q$, $q$Sussa Seemeeu$q$, $q$Boeta Seemeeu$q$, $q$Mamma en Pappa Seemeeu$q$]::text[]),
    ($q$n-happie-vir-n-hondjie$q$, $q$‘n Happie vir ‘n Hondjie$q$, $q$Blaffie leer om toertjies te doen vir belonings. Maar dan leer hy die belangrikste les: om die regte ding te doen, selfs wanneer daar nie 'n koekie of "happie" is nie. Hy kies om te luister omdat dit hom (en sy baas) gelukkig maak, nie net vir die beloning nie.$q$, array[$q$Doen die regte ding, want dit is wat ware blydskap bring$q$, $q$Jy hoef nie altyd ’n beloning te kry om gehoorsaam te wees nie$q$, $q$Goeie keuses laat jou van binne goed voel$q$]::text[], array[$q$Integriteit$q$, $q$Selfdissipline$q$, $q$Liefde$q$]::text[], array[$q$integriteit$q$, $q$selfdissipline$q$, $q$liefde$q$]::text[], array[$q$Hoekom wou Blaffie eers net luister?$q$, $q$Wat het gebeur toe hy besluit het om nie die gordyne te trek nie?$q$, $q$Hoekom is dit belangrik om te luister, selfs as niemand kyk nie?$q$]::text[], array[$q$Blaffie die hondjie$q$, $q$Blaffie se Baas$q$]::text[]),
    ($q$meerkruiertjie$q$, $q$Meerkruiertjie$q$, $q$'n Miskruier verloor sy geluk omdat hy sy bolletjie heeltyd vergelyk met ander s'n. Hy wil "meer" hê en word 'n "Meerkruier". Nadat hy alles verloor, besef hy dat dankbaarheid vir wat jy het, baie meer werd is as om die grootste of vinnigste te wees.$q$, array[$q$Moenie jouself aan ander meet of jouself vergelyk nie$q$, $q$Wees dankbaar vir wat jy het, selfs al voel dit min$q$, $q$Moet nooit jou eie waarde vergeet nie$q$]::text[], array[$q$Dankbaarheid$q$, $q$Selfaanvaarding$q$, $q$Tevredenheid$q$]::text[], array[$q$dankbaarheid$q$, $q$selfaanvaarding$q$, $q$tevredenheid$q$]::text[], array[$q$Waarom het die miskruier ophou glimlag terwyl hy sy bol rol?$q$, $q$Wat het met die groot bol gebeur toe hy te vinnig wou gaan?$q$, $q$Hoe het sy hart gevoel toe hy weer tevrede was met sy eie bolletjie?$q$]::text[], array[$q$Meerkruiertjie$q$, $q$Die Groter Miskruier$q$, $q$Die Vinnige Miskruier$q$]::text[]),
    ($q$die-ware-wenner$q$, $q$Die Ware Wenner$q$, $q$In die groot wedloop val Haas en kan hy nie klaarmaak nie. Skillie die skilpad kies om nie eerste oor die wenstreep te hardloop nie, maar om Haas op sy dop te tel en saam klaar te maak. Skillie wys dat vriendskap en omgee baie belangriker is as 'n goue medalje.$q$, array[$q$Vriendskap is ’n wedloop waarop geen eindstreep wag nie$q$, $q$’n Ware wenner help ander om ook die lyn te haal$q$, $q$Sukses beteken niks as jy nie jou vriende saam met jou neem nie$q$]::text[], array[$q$Vriendskap$q$, $q$Selfopoffering$q$, $q$Sportmanskap$q$]::text[], array[$q$vriendskap$q$, $q$selfopoffering$q$, $q$sportmanskap$q$]::text[], array[$q$Wat het Skillie gedoen wat almal verras het?$q$, $q$Wie het die medalje aan die einde gekry?$q$, $q$Wat maak iemand 'n "ware wenner" in die lewe?$q$]::text[], array[$q$Skillie$q$, $q$Haas$q$, $q$Knibbels$q$, $q$Skeidsregter Mossie$q$]::text[]),
    ($q$nee-en-dankie$q$, $q$Nee en Dankie!$q$, $q$Dankie is so gaaf dat mense oor hom loop omdat hy nie kan "nee" sê nie. Hy ontmoet die woordjie "Nee" en leer dat dit gesond is om grense te stel. Hy leer dat jy vriendelik EN ferm kan wees deur te sê: "Nee, dankie."$q$, array[$q$Jy mag "nee" sê as iets nie reg voel nie of as jy nie tyd het nie$q$, $q$"Nee, dankie" is 'n kragtige manier om vriendelik dog ferm te wees$q$, $q$Om grense te stel help jou om gelukkiger te wees$q$]::text[], array[$q$Selfrespek$q$, $q$Grense$q$, $q$Kommunikasie$q$]::text[], array[$q$selfrespek$q$, $q$grense$q$, $q$kommunikasie$q$]::text[], array[$q$Wat het gebeur omdat Dankie nie kon "nee" sê vir die irritasies nie?$q$, $q$Hoe het die irritasies gereageer toe hy "Nee, dankie" begin sê het?$q$, $q$Is daar tye wanneer jy ook moet leer om "Nee, dankie" te sê?$q$]::text[], array[$q$Dankie$q$, $q$Nee$q$, $q$Die Irritasies$q$]::text[]),
    ($q$die-kwaai-grommel-grom$q$, $q$Die Kwaai Grommel$q$, $q$Grommel is 'n outjie wat nie hou daarvan om te praat nie; hy grom sommer vir alles! Of Oupa nou sy kop vryf of Mamma hom vra om te help, sy antwoord is altyd "GROM!". Nadat hy sy boeta per ongeluk seermaak omdat hy nie sy woorde gebruik het om te sê hy wil alleen wees nie, leer hy dat dit baie beter is om te praat as om te grom.$q$, array[$q$Gebruik jou woorde om te sê hoe jy voel$q$, $q$As jy nie praat nie, weet niemand wat jy eintlik wil hê nie$q$, $q$Om te grom of te slaan maak net dinge moeilik; praat bring 'n oplossing$q$]::text[], array[$q$Kommunikasie$q$, $q$Selfbeheersing$q$, $q$Vriendelikheid$q$]::text[], array[$q$kommunikasie$q$, $q$selfbeheersing$q$, $q$vriendelikheid$q$]::text[], array[$q$Waarom het Grommel vir Oupa en Mamma gegrom?$q$, $q$Wat het gebeur toe Grommel vir Boeta gegrom en geslaan het?$q$, $q$Hoe voel dit vir ander mense as jy net grom en nie praat nie?$q$]::text[], array[$q$Kwaai Grommel$q$, $q$Oupa Grommel$q$, $q$Mamma Grommel$q$, $q$Boeta Grommel$q$]::text[]),
    ($q$schink-stories-die-kwaai-grommel-grom$q$, $q$Die Kwaai Grommel$q$, $q$Grommel is 'n outjie wat nie hou daarvan om te praat nie; hy grom sommer vir alles! Of Oupa nou sy kop vryf of Mamma hom vra om te help, sy antwoord is altyd "GROM!". Nadat hy sy boeta per ongeluk seermaak omdat hy nie sy woorde gebruik het om te sê hy wil alleen wees nie, leer hy dat dit baie beter is om te praat as om te grom.$q$, array[$q$Gebruik jou woorde om te sê hoe jy voel$q$, $q$As jy nie praat nie, weet niemand wat jy eintlik wil hê nie$q$, $q$Om te grom of te slaan maak net dinge moeilik; praat bring 'n oplossing$q$]::text[], array[$q$Kommunikasie$q$, $q$Selfbeheersing$q$, $q$Vriendelikheid$q$]::text[], array[$q$kommunikasie$q$, $q$selfbeheersing$q$, $q$vriendelikheid$q$]::text[], array[$q$Waarom het Grommel vir Oupa en Mamma gegrom?$q$, $q$Wat het gebeur toe Grommel vir Boeta gegrom en geslaan het?$q$, $q$Hoe voel dit vir ander mense as jy net grom en nie praat nie?$q$]::text[], array[$q$Kwaai Grommel$q$, $q$Oupa Grommel$q$, $q$Mamma Grommel$q$, $q$Boeta Grommel$q$]::text[]),
    ($q$bobbo-se-boeremusiek$q$, $q$Bobbo se Boeremusiek$q$, $q$Bobbo is 'n stout bobbejaan wat die boer se blomkool verwoes. Die boer besluit om nie meer kwaad te wees nie en begin konsertina speel. Bobbo word betower deur die musiek en ontdek dat hy 'n natuurlike talent daarvoor het! Die boer en Bobbo vergeet hul verskille en word die beste musiek-maats op die plaas.$q$, array[$q$Musiek en kuns kan vyande in vriende verander$q$, $q$Moenie dinge verniel wat aan ander behoort nie$q$, $q$Almal het 'n spesiale talent wat net wag om ontdek te word$q$]::text[], array[$q$Vergifnis$q$, $q$Vriendskap$q$, $q$Kreatiwiteit$q$]::text[], array[$q$vergifnis$q$, $q$vriendskap$q$, $q$kreatiwiteit$q$]::text[], array[$q$Wat het Bobbo met die boer se blomkool gedoen?$q$, $q$Hoe het die boer en Bobbo vriende geword?$q$, $q$Wat was Bobbo se spesiale talent?$q$]::text[], array[$q$Bobbo die Bobbejaan$q$, $q$Die Boer$q$]::text[]),
    ($q$fantjie-leer-skryf$q$, $q$Fantjie leer skryf$q$, $q$Fantjie die klein olifantjie wil vreeslik graag leer skryf, maar hy het nie hande nie. Hy probeer sy pote, maar dit werk nie. Dan ontdek hy sy slurp! Met baie geduld en oefening leer hy om die potlood vas te hou en uiteindelik skryf hy sy eie naam.$q$, array[$q$Moenie opgee as iets moeilik is nie; hou aan probeer$q$, $q$Gebruik die talente en dinge wat jy hét om jou drome te bereik$q$, $q$Oefening maak kuns!$q$]::text[], array[$q$Deursettingsvermoë$q$, $q$Selfvertroue$q$, $q$Geduld$q$]::text[], array[$q$deursettingsvermoë$q$, $q$selfvertroue$q$, $q$geduld$q$]::text[], array[$q$Waarom was Fantjie eers hartseer?$q$, $q$Watter deel van sy lyf het hy gebruik om die potlood vas te hou?$q$, $q$Wat was die eerste letter wat hy geleer skryf het?$q$]::text[], array[$q$Fantjie die Olifantjie$q$]::text[]),
    ($q$mamma-se-resieskar$q$, $q$Mamma se Resieskar$q$, $q$Mamma en Boeta is laat vir skool en sit vas in die verkeer. Om die spanning te breek, gebruik hulle hul verbeelding en tower Mamma se kar om in 'n pienk resieskar wat oor die verkeer kan spring! Hulle "wen" die resies en kom net betyds by die skool aan.$q$, array[$q$Jou verbeelding kan 'n slegte situasie in 'n lekker avontuur verander$q$, $q$Bly kalm wanneer dinge skeefloop$q$, $q$Mamma is 'n superheld wat alles vir haar kinders doen!$q$]::text[], array[$q$Positiwiteit$q$, $q$Verbeelding$q$, $q$Dankbaarheid$q$]::text[], array[$q$positiwiteit$q$, $q$verbeelding$q$, $q$dankbaarheid$q$]::text[], array[$q$Hoe het die kar in hul verbeelding gelyk?$q$, $q$Waarom was hulle so haastig daardie oggend?$q$, $q$Wat het Boeta aan die einde van die storie van sy mamma gesê?$q$]::text[], array[$q$Mamma$q$, $q$Boeta$q$, $q$Sussie en Ouboet$q$]::text[]),
    ($q$aarbeitjie$q$, $q$Aarbeitjie$q$, $q$Aarbeitjie is 'n oulike vrug, maar sy probeer "cool" wees deur lelik met Piesang te wees en Suurlemoentjie te blameer. Oom Pynie help haar om te besef dat sy nie ander hoef te beïndruk deur lelik te wees nie. Sy vra om verskoning en almal leer dat 'n "vrugteslaai" van vriende die beste is.$q$, array[$q$Moenie ander mense sleg sê net om "cool" te lyk nie$q$, $q$Moenie jou maats teen mekaar opstel nie$q$, $q$Ware vriende aanvaar jou net soos jy is, sonder dat jy hoef te jok$q$]::text[], array[$q$Eerlikheid$q$, $q$Vriendskap$q$, $q$Integriteit$q$]::text[], array[$q$eerlikheid$q$, $q$vriendskap$q$, $q$integriteit$q$]::text[], array[$q$Wat het Aarbeitjie gedoen wat Piesang kwaad gemaak het?$q$, $q$Waarom het sy vir Piesang gejok oor Suurlemoentjie?$q$, $q$Wat het Oom Pynie vir haar geleer oor die waarheid?$q$]::text[], array[$q$Aarbeitjie$q$, $q$Suurlemoentjie$q$, $q$Piesang$q$, $q$Oom Pynie$q$]::text[]),
    ($q$jan-die-brandweerman$q$, $q$Jan die Brandweerman$q$, $q$Jan is 'n flink brandweerman, maar wanneer sy eie stasie aan die brand slaan en sy water opraak, moet hy vinnig dink! Met die help van die Melkman en sy kat Vlammetjie, maak hy ‘n kreatiewe plan! Dit wys dat 'n goeie plan (en 'n bietjie spanwerk) enige probleem kan oplos.$q$, array[$q$Daar is altyd 'n oplossing as jy rustig bly en 'n plan maak$q$, $q$Spanwerk maak die werk makliker$q$, $q$Harde werk maak jou sterk!$q$]::text[], array[$q$Hulpvaardigheid$q$, $q$Kreatiewe denke$q$, $q$Moed$q$]::text[], array[$q$hulpvaardigheid$q$, $q$kreatiewe denke$q$, $q$moed$q$]::text[], array[$q$Waarmee het Jan die brand by die stasie geblus?$q$, $q$Wie is Vlammetjie?$q$, $q$Wat het die melkman gedoen om te help?$q$]::text[], array[$q$Jan die Brandweerman$q$, $q$Vlammetjie die kat$q$, $q$Die Melkman$q$]::text[]),
    ($q$maatjie-die-akker-saadjie$q$, $q$Maatjie die Akker-saadjie$q$, $q$Maatjie is 'n klein akker-saadjie met 'n groot droom om 'n boom te word. Sy pad is egter vol hindernisse: hy word geskop, amper deur 'n voëltjie opgeëet, en beland in 'n donker broeksak. Net toe hy dink alles is verlore, plant 'n juffrou hom in die grond. Maatjie leer dat moeilike tye (soos om in die donker grond gedruk te word) soms nodig is om te groei tot dit wat jy bestem is om te wees.$q$, array[$q$Moenie moed opgee as dinge moeilik gaan nie; dit kan deel van jou groei wees$q$, $q$Groot drome neem tyd en geduld$q$, $q$Soms moet jy eers "begrawe" word voordat jy kan "ontkiem."$q$]::text[], array[$q$Deursettingsvermoë$q$, $q$Geduld$q$, $q$Hoop$q$]::text[], array[$q$deursettingsvermoë$q$, $q$geduld$q$, $q$hoop$q$]::text[], array[$q$Watter gevare moes Maatjie trotseer voordat hy geplant is?$q$, $q$Hoe het die muntstuk Maatjie se lewe gered?$q$, $q$Wat het Maatjie se naam aan die einde van die storie geword?$q$]::text[], array[$q$Maatjie (die akker-saadjie)$q$, $q$Die kind wat hom skop$q$, $q$Die voëltjie$q$, $q$Die seuntjie$q$, $q$Die dogtertjie$q$, $q$Juffrou$q$, $q$Oom Boom$q$]::text[]),
    ($q$slappie-en-sloep$q$, $q$Slappie & Sloep$q$, $q$Slappie is "cool" en ontspanne, maar hy stel alles uit. Sloep is netjies en glo daaraan om werk dadelik klaar te maak. Wanneer Slappie in die moeilikheid beland by die lekkernyfabriek omdat hy te veel gedans en te min gewerk het, help Sloep hom. Slappie leer dat selfdissipline eintlik baie "cooler" is omdat dit jou vry maak van bekommernis.$q$, array[$q$Doen dit sommer, dan hoef jy nie later te bekommer nie$q$, $q$Om verantwoordelik te wees is 'n goeie eienskap wat ander help$q$, $q$Spanwerk kan 'n groot werk vinnig klaarmaak$q$]::text[], array[$q$Verantwoordelikheid$q$, $q$Selfdissipline$q$, $q$Hulpvaardigheid$q$]::text[], array[$q$verantwoordelikheid$q$, $q$selfdissipline$q$, $q$hulpvaardigheid$q$]::text[], array[$q$Wat is Slappie se leuse (motto) aan die begin van die storie?$q$, $q$Hoe het Sloep vir Slappie by die fabriek gehelp?$q$, $q$Hoekom is dit beter om jou werk dadelik te doen?$q$]::text[], array[$q$Slappie$q$, $q$Sloep$q$, $q$Die ander werkers$q$, $q$Die fabriekbaas$q$]::text[]),
    ($q$dankie-en-die-huil-oor-alles$q$, $q$Dankie en die Huil-oor-alles$q$, $q$In Woordjieland woon 'n karakter wat huil oor alles om sy sin te kry. Hy dink trane is die manier om mense se antwoorde te verander. Dankie leer hom egter dat dit baie beter is om mooi te luister en redes te verstaan as om net lawaai te maak. Die Huil-oor-alles verander sy naam (en sy hart) na "Die Mooi Luister."$q$, array[$q$Jy kan nie huil of raas om jou sin te kry nie$q$, $q$Om mooi te luister help jou om te verstaan hoekom dinge gebeur$q$, $q$Tevredenheid bring meer geluk as om heeltyd aan te dring op jou eie sin$q$]::text[], array[$q$Selfbeheersing$q$, $q$Luistervaardighede$q$, $q$Tevredenheid$q$]::text[], array[$q$selfbeheersing$q$, $q$luistervaardighede$q$, $q$tevredenheid$q$]::text[], array[$q$Waarom het die Huil-oor-alles altyd gehuil?$q$, $q$Wat het Dankie gedoen toe die Huil-oor-alles begin huil het oor die geskenk?$q$, $q$Wat is die Huil-oor-alles se nuwe naam?$q$]::text[], array[$q$Dankie$q$, $q$Die Huil-oor-alles (later Die Mooi Luister)$q$]::text[]),
    ($q$die-fluistervarke-en-die-hoed-wat-groet$q$, $q$Die Hoed wat Groet$q$, $q$Drie wildevark-boeties (die Fluistervarke) skrik hulle boeglam vir 'n hoed wat self loop en snork. Hulle bekruip die "lewendige hoed" met groot versigtigheid, net om uit te vind dat dit glad nie 'n monster is nie, maar hul eie kleinboetie wat onder die hoed wegkruip!$q$, array[$q$Dinge waarvoor ons bang is, is dikwels glad nie so gevaarlik as ons dit van naderby bekyk nie$q$, $q$Pas op na mekaar en moenie jou boeties of sussies verloor nie$q$, $q$Lag is die beste medisyne vir skrik$q$]::text[], array[$q$Moed$q$, $q$Familie-liefde$q$, $q$Speelsheid$q$]::text[], array[$q$moed$q$, $q$familie-liefde$q$, $q$speelsheid$q$]::text[], array[$q$Wie se name is almal Fluistervarke?$q$, $q$Waarom het die varkies gedink die hoed is lewendig?$q$, $q$Wie was eintlik onder die hoed weggekruip?$q$]::text[], array[$q$Ompel$q$, $q$Strompel$q$, $q$Snoet$q$, $q$Kleinboet$q$, $q$Mamma Vark$q$]::text[]),
    ($q$rudi-renoster-speel-rof$q$, $q$Rudi Renoster speel rof$q$, $q$Rudi is ’n opgewonde renostertjie wat dol is oor speel, maar hy besef nie hoe sterk hy is nie. By die skool gooi hy die bal te hard vir Muis, tackle die Springbokkies te rof en hardloop die Cheetah-maatjies omver. Wanneer niemand meer met hom wil speel nie, leer Rudi dat hy sy krag moet beheer en versigtig moet wees met sy maatjies.$q$, array[$q$Wees bedagsaam teenoor ander se grootte en krag$q$, $q$Om "mooi" te speel is belangriker as om te wen of te "tackle."$q$, $q$As jy iemand seergemaak het, vra om verskoning en probeer weer$q$]::text[], array[$q$Bedagsaamheid$q$, $q$Selfbeheersing$q$, $q$Vergifnis$q$]::text[], array[$q$bedagsaamheid$q$, $q$selfbeheersing$q$, $q$vergifnis$q$]::text[], array[$q$Waarom wou die Springbokkies vir Rudi 'n "rooi kaart" gee?$q$, $q$Hoe het Rudi sy gedrag verander die volgende dag?$q$, $q$Hoekom is dit belangrik om nie "rof" te wees met kleiner maatjies nie?$q$]::text[], array[$q$Rudi Renoster$q$, $q$Rudi se Pappa en Mamma$q$, $q$Muis$q$, $q$Volstruis$q$, $q$Die Springbokkies$q$, $q$Die Cheetah-maatjies$q$]::text[]),
    ($q$dankie-en-wilnie-deelnie$q$, $q$Dankie en Wilnie Deelnie$q$, $q$Wilnie Deelnie is 'n woordjie wat alles vir homself wil hê en "MYNE!" skree vir alles. Hy koop selfs al die roomys by die trokkie sodat niemand anders kan kry nie. Maar die roomys smelt en hy kan nie alles alleen hanteer nie. Dankie wys vir hom onbaatsugtige liefde deur sy eie roomys met hom te deel, en Wilnie leer dat deel eintlik baie lekkerder is.$q$, array[$q$As jy alles vir jouself hou, eindig jy dikwels met niks (of gesmelte roomys!)$q$, $q$Deel bring mense bymekaar en maak jou gelukkig$q$, $q$Vriendelikheid kan iemand se karakter verander$q$]::text[], array[$q$Vrygewigheid$q$, $q$Mededeelsaamheid$q$, $q$Vriendelikheid$q$]::text[], array[$q$vrygewigheid$q$, $q$mededeelsaamheid$q$, $q$vriendelikheid$q$]::text[], array[$q$Wat het met al die roomys gebeur wat Wilnie gekoop het?$q$, $q$Wat het Dankie gedoen toe Wilnie sy roomys verloor het?$q$, $q$Wat is Wilnie Deelnie se nuwe naam aan die einde?$q$]::text[], array[$q$Dankie$q$, $q$Wilnie Deelnie (later Wil Deel)$q$, $q$Die ander Woordjies$q$, $q$Die Roomysman$q$]::text[]),
    ($q$muggie-maak-maats$q$, $q$Muggie maak maats$q$, $q$Muggie is nuut by die insekte-skool en soek desperaat 'n maat. Die groot kewer lag vir hom omdat hy klein is, die vlieg dink hy is te stadig, en die muskiet wil net stout wees. Muggie besluit dan om self 'n goeie maat te wees vir Wim Wurm, vir wie almal lag. Hulle pret is so aansteeklik dat selfs die ander insekte later wil saamspeel.$q$, array[$q$Moenie net 'n goeie maat soek nie, wees self een$q$, $q$Ware vriendskap gaan nie oor hoe groot, vinnig of "cool" jy is nie$q$, $q$Goeie maatjies aanvaar mekaar net soos hulle is$q$]::text[], array[$q$Aanvaarding$q$, $q$Vriendskap$q$, $q$Goedhartigheid$q$]::text[], array[$q$aanvaarding$q$, $q$vriendskap$q$, $q$goedhartigheid$q$]::text[], array[$q$Waarom wou die Muskiet nie eintlik 'n goeie maat vir Muggie wees nie?$q$, $q$Wat het Muggie vir Wim Wurm gedoen wat hom laat vlieg het?$q$, $q$Wat is die "geheim" om maatjies te maak waarvan die storie praat?$q$]::text[], array[$q$Muggie$q$, $q$Tom Tor (die kewer)$q$, $q$Vlieg$q$, $q$Muskiet$q$, $q$Wim Wurm$q$]::text[]),
    ($q$daar-is-n-leeu-in-my-dak$q$, $q$Daar is ‘n Leeu in my dak$q$, $q$Klein Boeloe hoor elke aand 'n vreeslike brulgeluid in haar kamer en is oortuig daar is 'n leeu in die dak. Haar Pappa soek oral, maar kry niks. Uiteindelik ontdek sy die waarheid: die "leeu" is eintlik iets baie meer snaaks.... Sy besef daar was nooit rede om bang te wees nie en leer om saam met die "snork-leeu" te lag.$q$, array[$q$Baie dinge waarvoor ons bang is in die donker, het 'n logiese (en soms snaakse) verduideliking$q$, $q$Praat met jou ouers as jy bang is$q$, $q$Humor kan vrees wegneem$q$]::text[], array[$q$Moed$q$, $q$Vertroue$q$, $q$Familie-humor$q$]::text[], array[$q$moed$q$, $q$vertroue$q$, $q$familie-humor$q$]::text[], array[$q$Waar het Boeloe gedink die leeu wegkruip?$q$, $q$Wat was die brulgeluid eintlik?$q$, $q$Waarom het Mamma gesê daar is nou "twee snork-leeutjies" in die bed?$q$]::text[], array[$q$Boeloe$q$, $q$Pappa$q$, $q$Mamma$q$, $q$Boetie$q$]::text[]),
    ($q$daar-s-n-leeu-in-my-dak$q$, $q$Daar is ‘n Leeu in my dak$q$, $q$Klein Boeloe hoor elke aand 'n vreeslike brulgeluid in haar kamer en is oortuig daar is 'n leeu in die dak. Haar Pappa soek oral, maar kry niks. Uiteindelik ontdek sy die waarheid: die "leeu" is eintlik iets baie meer snaaks.... Sy besef daar was nooit rede om bang te wees nie en leer om saam met die "snork-leeu" te lag.$q$, array[$q$Baie dinge waarvoor ons bang is in die donker, het 'n logiese (en soms snaakse) verduideliking$q$, $q$Praat met jou ouers as jy bang is$q$, $q$Humor kan vrees wegneem$q$]::text[], array[$q$Moed$q$, $q$Vertroue$q$, $q$Familie-humor$q$]::text[], array[$q$moed$q$, $q$vertroue$q$, $q$familie-humor$q$]::text[], array[$q$Waar het Boeloe gedink die leeu wegkruip?$q$, $q$Wat was die brulgeluid eintlik?$q$, $q$Waarom het Mamma gesê daar is nou "twee snork-leeutjies" in die bed?$q$]::text[], array[$q$Boeloe$q$, $q$Pappa$q$, $q$Mamma$q$, $q$Boetie$q$]::text[]),
    ($q$kokketiel-se-kuif$q$, $q$Kokketiel se kuif$q$, $q$Kokketiel is baie trots op sy "cool" kuif en wil nie hê dit moet deurmekaar waai nie. Daarom wil hy nie saam met Peppie die Parakiet speel nie. Hy besef egter later dat hy eensaam is terwyl hy "cool" lyk, terwyl die ander voëls pret het. Hy besluit om sy kuif te vergeet en saam te speel, en ontdek die nuwe "Spoedkuif"-styl!$q$, array[$q$Hoe jy lyk is nie so belangrik soos die pret wat jy saam met vriende het nie$q$, $q$Moenie toelaat dat ydelheid (om mooi te wil wees) jou verhinder om herinneringe te maak nie$q$, $q$Om 'n maat te hê is 'n beter gevoel as om net "cool" te lyk$q$]::text[], array[$q$Vriendskap$q$, $q$Nederigheid$q$, $q$Vreugde$q$]::text[], array[$q$vriendskap$q$, $q$nederigheid$q$, $q$vreugde$q$]::text[], array[$q$Waarom was Kokketiel eers kwaad vir Peppie?$q$, $q$Wat het Kokketiel laat besluit om tog saam te speel?$q$, $q$Hoe maak mens 'n "Spoedkuif"?$q$]::text[], array[$q$Kokkie Kokketiel$q$, $q$Peppie die Parakiet$q$, $q$Die ander voëltjies by die fontein$q$]::text[])
)
, updated as (
    update public.stories as story
    set
        summary = updates.synopsis,
        description = updates.synopsis,
        tags = (
            select coalesce(array_agg(tag order by tag), array[]::text[])
            from (
                select distinct lower(btrim(tag)) as tag
                from unnest(coalesce(story.tags, array[]::text[]) || coalesce(updates.value_tags, array[]::text[])) as tag
                where tag is not null
                  and btrim(tag) <> ''
            ) as merged_tags
        ),
        metadata = jsonb_set(
            coalesce(story.metadata, '{}'::jsonb),
            '{story_details}',
            jsonb_build_object(
                'source', 'Storie Pakkie Inligting.docx',
                'source_title', updates.source_title,
                'synopsis', updates.synopsis,
                'lessons', to_jsonb(updates.lessons),
                'values', to_jsonb(updates.values_display),
                'value_tags', to_jsonb(updates.value_tags),
                'conversation_questions', to_jsonb(updates.questions),
                'characters', to_jsonb(updates.characters),
                'imported_at_utc', to_char(timezone('utc', now()), 'YYYY-MM-DD"T"HH24:MI:SS"Z"')
            ),
            true
        )
    from updates
    where story.slug = updates.slug
    returning story.slug
)
select
    (select count(*) from updates) as requested_updates,
    (select count(*) from updated) as applied_updates,
    (select array_agg(slug order by slug) from updated) as updated_slugs;

